var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"이런, 멍청이들!","JPN":"うう、バカどもが！","ENG":"You fools!","TWN":"這群蠢貨！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"엘릭서는 규정된 타입만 파는 거라고 누누이 얘기했잖아!","JPN":"エリクサーは規定のタイプだけ売るようにと何度も言っただろう！","ENG":"How many times do I have to tell you that there are certain types of Elixirs we can sell!","TWN":"我不是說過好幾次，聖水只能販賣規定的類型嗎！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"네가 가져간 건 인자 배양용...... 아니, 신세계로 가기 위한 아주 특별한 엘릭서였단 말이다!","JPN":"お前が持ち出したのはファクター培養の……\\nいや、新世界に行くための非常に特別なエリクサーだったんだぞ！","ENG":"What you took was for incuba— I mean, the one we need to transcend into the new world!","TWN":"你拿走的那個是培養因子用……不，是前往新世界，極其特別的聖水啊！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"그런걸 동네 여고생에게 팔아먹다니...... 제정신이냐! 엘카노 주교!!","JPN":"そんなものを平凡な女子高生に売るなんて……\\n正気なのか！　エルカノ司教！！","ENG":"And you sold it to a bloody high school student? Are you out of your mind? Bishop Elcano!","TWN":"你竟然把這東西賣給了社區裡的女高中生……你瘋了嗎！埃爾卡諾主教！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"죄, 죄송합니다! 이번 달 상납금이 부족해서 그만......","JPN":"も、申し訳ありません！　今月の上納金が足りなくてつい……","ENG":"I-I'm sorry! I was falling short on this month's payoff, so...","TWN":"非、非常抱歉！因為這個月要繳的會費有些不夠，實在沒辦法所以……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"주, 주교님...... 상납금이라뇨? 분명 천사님들께 올릴 헌금을 모은다고 하지 않으셨습니까?","JPN":"し、司教……上納金ってどういうことですか？\\n天使様に捧げる献金を集めるとおっしゃいませんでしたか？","ENG":"B-Bishop! What payoff? Didn't you say it was to offer to the angels?","TWN":"主、主教大人……您說會費？您不是說那是籌集要捐給天使的奉獻嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"에잇, 전부 시끄러워! 그 엘릭서를 회수하지 못하면 너희는 낙원에서 영원히 제명이다!","JPN":"ええい、うるさい！\\nそのエリクサーを回収できないなら、お前たちは楽園から永遠に除名だ！","ENG":"Gah! Shut up, all of you! Bring me that Elixir, or all of you will be expelled from the paradise! Forever!","TWN":"欸，你們都吵死了！如果沒辦法回收那個聖水，你們就永遠從樂園中除名了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"당장 되찾아오도록!","JPN":"今すぐ取り戻してこい！","ENG":"Now sod off!","TWN":"馬上去找回來！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"하, 하지만 그건 이미 경찰 손에 넘어갔습니다.","JPN":"し、しかしあれは、すでに警察の手に渡りました。","ENG":"B-but the police have already gotten hold of it.","TWN":"但、但是它已經被交到了警察手裡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"아무리 그래도, 또 경찰서에 쳐들어가는 건 좀......","JPN":"いくら何でも、また警察庁に乗り込むのは……","ENG":"And... I'm not sure about raiding the police station again...","TWN":"就算是這樣，又要闖入警察廳恐怕有點……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"흥, 경찰도 결국 인간일 뿐이다. 천사님들께서 가호하시는 우리가 두려울 것은 없다!","JPN":"ふん、警察も所詮人間だ。天使様のご加護を受ける私たちに恐れるものは何もない！","ENG":"Hmpf, the police are only human. There's nothing to fear. The angels will protect us!","TWN":"哼！警察也不過是人類，有天使們保佑的我們沒什麼好怕的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그, 그렇게 말씀하셔도......","JPN":"そ、そうおっしゃられても……","ENG":"E-even so...","TWN":"就算您這麼說……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"믿음이 부족한 놈 같으니! 이것을 보아라!!","JPN":"信仰心が足りないやつだな！　これを見ろ！！","ENG":"Oh, ye of little faith! Behold!","TWN":"你這缺乏信仰的人啊！看看這個！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이, 이건?!!","JPN":"こっ、これは！！？","ENG":"That's...","TWN":"這、這是？！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"이것이 바로 지난주에 천사님들께서 내려주신 마젤란의 신수인 것이다!","JPN":"これは先週、天使様が与えてくださったマジェランの神獣なのだ！","ENG":"This is the divine beast that the angels bestowed upon us last week!","TWN":"這就是上週天使大人賜予的麥哲倫神獸！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"오오! 이것이!!","JPN":"おお！　これが！！","ENG":"*Gasps* The divine beast!","TWN":"哦哦！這就是！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"신수님들께서 우릴 위해 싸워주신다니! 이렇게 황송하고 은혜로울 데가!","JPN":"神獣が俺たちのために戦ってくださる！\\nなんて畏れ多くてありがたいことなんだ！","ENG":"The fierce divine beast is going to fight for us! What a blessing this is!","TWN":"神獸大人們竟然會為我們戰鬥！這真是誠惶誠恐，滿是恩典的時刻！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MAGELLAN_MAGELLAN_NULL_NULL","text":{"KOREA":"실패는 용납하지 않겠다. 모든 걸 바쳐 성공시키도록!","JPN":"失敗は許さない。すべてを捧げて成功させるんだ！","ENG":"I won't tolerate failure. Put your hearts and souls into this sacred mission!","TWN":"不允許失敗。獻出一切並取得成功吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAGELLAN_MAGELLAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"물론입니다! 반드시 성전에서 승리하여 기대에 부응하겠습니다!","JPN":"もちろんです！　ご期待に沿えるよう、必ず聖戦に勝利します！","ENG":"Absolutely. I won't let you down. I will emerge victorious in this holy war!","TWN":"當然！我們一定會在聖戰中取得勝利，回應麥哲倫大人的期待！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};